#include <stdio.h>
int main(){
    const char *week[4] = {"Monday","Tuesday","Wednesday","Thursday"};
    int T = 1; // single execution as there is no input
    for(int tc = 0; tc < T; ++tc){
        printf("%s\n%s\n", week[2], week[3]);
    }
    return 0;
}

